    -- SK Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_1, 'sk', 
        'Daňové kontroly a najčastejšie nedostatky v transferovom oceňovaní',
        'Cieľom daňovej kontroly je preskúmanie postupov daňovníka pri určovaní transferových cien, t. j. či si zvolil vhodnú transferovú metódu, či disponuje dostatočnou dokumentáciou k preverovaným transakciám.',
        'Cieľom daňovej kontroly je preskúmanie postupov daňovníka pri určovaní transferových cien, t. j. či si zvolil vhodnú transferovú metódu, či disponuje dostatočnou dokumentáciou k preverovaným transakciám, či vie transparentne podať vysvetlenia k jednotlivým prípadom, či si vybral správnu základňu pre porovnávaciu analýzu a teda či vie dostatočne preukázať uplatnenie princípu nezávislého vzťahu v ním realizovaných závislých transakciách počas daného zdaňovacieho obdobia.',
        'Daňové právo', '8 min čítania',
        '<h2>Cieľ a priebeh daňovej kontroly</h2><p>Všeobecný priebeh daňovej kontroly upravujú ustanovenia § 44 až § 47 zákona č. 563/2009 Z. z. o správe daní (daňový poriadok) a o zmene a doplnení niektorých zákonov (ďalej len „daňový poriadok“). Cieľom daňovej kontroly je preskúmanie postupov daňovníka pri určovaní transferových cien, t. j. či si zvolil vhodnú transferovú metódu, či disponuje dostatočnou dokumentáciou k preverovaným transakciám, či vie transparentne podať vysvetlenia k jednotlivým prípadom, či si vybral správnu základňu pre porovnávaciu analýzu a teda či vie dostatočne preukázať uplatnenie princípu nezávislého vzťahu v ním realizovaných závislých transakciách počas daného zdaňovacieho obdobia.</p><h3>Začatie a oznámenie o daňovej kontrole</h3><p>Podľa ustanovenia § 44 daňového poriadku daňová kontrola začína dňom určeným správcom dane a o ktorom informuje daňovníka prostredníctvom oznámenia. Oznámenie musí obsahovať aj miesto výkonu kontroly, druh dane, ktorej sa kontrola týka, kontrolované obdobie a lehotu na predloženie požadovanej dokumentácie spolu s poučením o následkoch nevyhovenia. Správca dane môže začať daňovú kontrolu aj bez oznámenia, ak má podozrenie, že daňovník pozmení alebo zlikviduje doklady potrebné pre posúdenie prípadu.</p><p>Ak správca dane počas prebiehajúcej daňovej kontroly identifikuje nezrovnalosti aj v iných obdobiach, ako sú uvedené v oznámení, je oprávnený rozšíriť kontrolu aj na tieto obdobia.</p><h3>Povinnosti daňovníka počas kontroly</h3><p>Daňovník je povinný umožniť správcovi dane vykonať kontrolu, sprístupniť mu priestory a svoj softvér, spolupracovať a zapožičať mu podklady aj mimo svojich priestorov, ak o to správca dane požiada.</p><p>Počas kontroly správca dane preveruje predložené doklady z hľadiska ich správnosti, úplnosti a pravdivosti. Ak identifikuje nezrovnalosti, informuje o tom daňovníka a žiada od neho vysvetlenie. Daňovník môže predložiť akékoľvek doklady a poskytnúť dôkazy a vysvetlenia k prípadu, ktoré následne správca dane vyhodnocuje. Ak sú podklady alebo vysvetlenia nedostatočné, žiada o doplnenie.</p><h2>Najčastejšie preverované oblasti</h2><p>Z hľadiska preverovaných oblastí, najčastejším predmetom kontrol je oblasť služieb, tovarov a nehmotného majetku. Okrem toho sa bežne preveruje aj rozdelenie nákladov medzi závislé osoby a skupinové financovanie.</p><p>Samotná kontrola sa vykonáva prostredníctvom správcom dane vybraných vzoriek, o predloženie ktorých následne žiada daňovníka. Dôvodom výberu konkrétnej vzorky kontrolovanej transakcie môže byť jej početnosť v rámci celkovej činnosti daňovníka. Výber vzorky môže byť ovplyvnený aj podozrením správcu dane, napríklad ak daňovník mení biznis model, prípadne medziročne prechádza zo zisku do straty. Správcovia dane takisto bežne otvárajú daňové kontroly u problémových daňovníkov, napríklad u takých, u ktorých už v minulosti k dorubeniu dane prišlo alebo u takých, ktorí realizujú rizikové transakcie.</p><h3>Čo správcovia dane preverujú</h3><p>Pri daňovej kontrole správcovia dane preverujú najmä:</p><ul><li>či k predmetu plnenia skutočne prišlo, resp. boli služby dodané,</li><li>či spoločnosť predmet plnenia, resp. dodané služby skutočne potrebovala, t. j. správca dane sa pýta, či by si kontrolovaný subjekt takúto službu zaobstaral aj u nezávislej osoby,</li><li>či boli ceny stanovené v súlade s princípom nezávislého vzťahu.</li></ul><h2>Najčastejšie identifikované problémy</h2><p>Medzi najčastejšie identifikované problémy pri daňových kontrolách patria:</p><ul><li><strong>neschopnosť spoločnosti dostatočne vysvetliť dodané služby medzi závislými osobami;</strong> daňovník musí nepochybne preukázať, že dodaná služba bola opodstatnená, t. j. súvisí s potrebami prijímateľa a je v súlade s princípom nezávislého vzťahu,</li><li><strong>nedostatočná alebo žiadna transferová dokumentácia,</strong></li><li><strong>nízka kvalita transferovej dokumentácie,</strong></li><li><strong>nesúlad obsahu dokumentácie s podnikateľskou činnosťou daňovníka a jeho vysvetleniami,</strong></li><li><strong>nedostatočné zdôvodnenie faktorov porovnateľnosti,</strong> t. j. nedostatočná funkčná a riziková analýza, napríklad príliš malá alebo nesprávne zvolená porovnávacia základňa,</li><li><strong>nedostatočné vysvetlenie nižšej úrovne zisku spoločnosti v porovnaní s ostatnými spoločnosťami v skupine,</strong></li><li><strong>neexistencia zmlúv a iných podkladov, ktoré by podporili zvolený postup daňovníka,</strong></li><li><strong>neschopnosť poskytnúť správcom dane žiadané informácie o závislých osobách,</strong></li><li><strong>pomalosť, problematickosť alebo neschopnosť daňovníka reagovať na rôzne dopyty zo strany správcu dane.</strong></li></ul><p>Priebeh a výsledok daňovej kontroly nepochybne ovplyvňuje prístup kontrolovaného daňovníka k problematike transferového oceňovania. Ak správca dane zistí, že daňovník vynaložil v procese dokumentovania maximálne úsilie a toto úsilie sa prejavilo vo vysokej kvalite predloženej dokumentácie, môže to proces daňovej kontroly urýchliť, napríklad schválením použitej metódy, prijatím vysvetlení spoločnosti bez potreby hlbšieho preverovania, čo v konečnom dôsledku vedie k nedorubeniu dane.</p>',
        ARRAY['transferové oceňovanie', 'daňová kontrola', 'dokumentácia', 'compliance'],
        TRUE
    );

    -- EN Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_1, 'en', 
        'Tax control and most common deficiencies in transfer pricing',
        'The purpose of the tax audit is to examine the taxpayer''s procedures for determining transfer prices, i.e. whether they chose an appropriate transfer method, whether they have sufficient documentation for the audited transactions.',
        'The general course of a tax audit is regulated by provisions § 44 to § 47 of Act No. 563/2009 Coll. on Tax Administration (Tax Procedure Code) and on amendments to certain laws (hereinafter "Tax Procedure Code"). The goal of a tax audit is to examine the taxpayer''s procedures in determining transfer prices, i.e. whether they chose an appropriate transfer method, whether they have sufficient documentation for the verified transactions, whether they can transparently provide explanations for individual cases, whether they chose the right base for the comparability analysis and therefore whether they can sufficiently demonstrate the application of the arm''s length principle in the related transactions they performed during the given tax period.',
        'Tax Law', '8 min read',
        '<h2>Purpose and course of tax audit</h2><p>The general course of a tax audit is regulated by provisions § 44 to § 47 of Act No. 563/2009 Coll. on Tax Administration (Tax Procedure Code) and on amendments to certain laws (hereinafter "Tax Procedure Code"). The goal of a tax audit is to examine the taxpayer''s procedures in determining transfer prices, i.e. whether they chose an appropriate transfer method, whether they have sufficient documentation for the verified transactions, whether they can transparently provide explanations for individual cases, whether they chose the right base for the comparability analysis and therefore whether they can sufficiently demonstrate the application of the arm''s length principle in the related transactions they performed during the given tax period.</p><h3>Commencement and notification of tax audit</h3><p>According to provision § 44 of the Tax Procedure Code, a tax audit begins on the day determined by the tax administrator and about which they inform the taxpayer through a notification. The notification must also contain the place of the audit, the type of tax subject to audit, the audited period and the deadline for submitting the required documentation along with instructions on the consequences of non-compliance. The tax administrator may start a tax audit even without notification if they suspect that the taxpayer will alter or destroy documents necessary for assessing the case.</p><p>If the tax administrator, during an ongoing tax audit, identifies discrepancies in periods other than those mentioned in the notification, they are entitled to extend the audit to these periods as well.</p><h3>Taxpayer''s obligations during the audit</h3><p>The taxpayer is obliged to allow the tax administrator to perform the audit, provide access to premises and their software, cooperate and lend materials even outside their premises if the tax administrator requests it.</p><p>During the audit, the tax administrator examines the submitted documents in terms of their correctness, completeness and truthfulness. If they identify discrepancies, they inform the taxpayer and ask for an explanation. The taxpayer can submit any documents and provide evidence and explanations for the case, which the tax administrator then evaluates. If the documents or explanations are insufficient, they request a supplement.</p><h2>Most frequently audited areas</h2><p>In terms of audited areas, the most frequent subject of audits is the area of services, goods and intangible assets. In addition, the distribution of costs between related persons and group financing are commonly examined.</p><p>The audit itself is carried out through samples selected by the tax administrator, the submission of which they subsequently request from the taxpayer. The reason for choosing a specific sample of a controlled transaction may be its frequency within the overall activity of the taxpayer. The selection of the sample may also be influenced by the suspicions of the tax administrator, for example, if the taxpayer changes their business model or switches from profit to loss year-on-year. Tax administrators also commonly open tax audits for problematic taxpayers, for example, those who have already had a tax reassessment in the past or those who carry out risky transactions.</p><h3>What tax administrators check</h3><p>During a tax audit, tax administrators primarily check:</p><ul><li>whether the object of the performance actually occurred, or services were delivered,</li><li>whether the company actually needed the object of the performance or delivered services, i.e. the tax administrator asks whether the audited entity would have procured such a service from an independent person as well,</li><li>whether the prices were set in accordance with the arm''s length principle.</li></ul><h2>Most commonly identified problems</h2><p>Among the most commonly identified problems in tax audits are:</p><ul><li><strong>the company''s inability to adequately explain the services provided between related persons;</strong> the taxpayer must undoubtedly prove that the delivered service was justified, i.e. it is related to the recipient''s needs and is in accordance with the arm''s length principle,</li><li><strong>insufficient or no transfer documentation,</strong></li><li><strong>low quality of transfer documentation,</strong></li><li><strong>inconsistency of the content of the documentation with the taxpayer''s business activity and their explanations,</strong></li><li><strong>insufficient justification of comparability factors,</strong> i.e. insufficient functional and risk analysis, for example, a comparability base that is too small or incorrectly chosen,</li><li><strong>insufficient explanation of the lower profit level of the company compared to other companies in the group,</strong></li><li><strong>the non-existence of contracts and other documents that would support the taxpayer''s chosen procedure,</strong></li><li><strong>inability to provide the requested information about related persons to the tax administrator,</strong></li><li><strong>slowness, problematic nature or inability of the taxpayer to respond to various inquiries from the tax administrator.</strong></li></ul><p>The course and outcome of a tax audit are undoubtedly influenced by the audited taxpayer''s approach to the issue of transfer pricing. If the tax administrator finds that the taxpayer has made maximum effort in the documentation process and this effort has been reflected in the high quality of the submitted documentation, it can speed up the tax audit process, for example, by approving the method used, accepting the company''s explanations without the need for deeper verification, which ultimately leads to no additional tax assessment.</p>',
        ARRAY['transfer pricing', 'tax audit', 'documentation', 'compliance'],
        TRUE
    );

    -- DE Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_1, 'de', 
        'Steuerprüfung und häufigste Mängel bei der Verrechnungspreisgestaltung',
        'Zweck der Betriebsprüfung ist die Prüfung der Verfahren des Steuerpflichtigen zur Ermittlung von Verrechnungspreisen, d.h. ob er eine geeignete Verrechnungsmethode gewählt hat, ob er über eine ausreichende Dokumentation für die geprüften Geschäftsvorfälle verfügt.',
        'Der allgemeine Ablauf einer Betriebsprüfung ist in den Bestimmungen der §§ 44 bis 47 des Gesetzes Nr. 563/2009 Ges. über die Steuerverwaltung (Steuerordnung) und über Änderungen einiger Gesetze (im Folgenden „Steuerordnung“) geregelt. Ziel einer Betriebsprüfung ist die Prüfung der Vorgehensweise des Steuerpflichtigen bei der Ermittlung von Verrechnungspreisen, d. h. ob er eine geeignete Verrechnungsmethode gewählt hat, ob er über eine ausreichende Dokumentation für die geprüften Transaktionen verfügt, ob er Erläuterungen zu den einzelnen Fällen transparent abgeben kann, ob er die richtige Basis für die Vergleichbarkeitsanalyse gewählt hat und somit die Anwendung des Fremdvergleichsgrundsatzes bei den von ihm im jeweiligen Besteuerungszeitraum getätigten abhängigen Transaktionen ausreichend nachweisen kann.',
        'Steuerrecht', '8 min Lesezeit',
        '<h2>Zweck und Ablauf der Betriebsprüfung</h2><p>Der allgemeine Ablauf einer Betriebsprüfung ist in den Bestimmungen der §§ 44 bis 47 des Gesetzes Nr. 563/2009 Ges. über die Steuerverwaltung (Steuerordnung) und über Änderungen einiger Gesetze (im Folgenden „Steuerordnung“) geregelt. Ziel einer Betriebsprüfung ist die Prüfung der Vorgehensweise des Steuerpflichtigen bei der Ermittlung von Verrechnungspreisen, d. h. ob er eine geeignete Verrechnungsmethode gewählt hat, ob er über eine ausreichende Dokumentation für die geprüften Transaktionen verfügt, ob er Erläuterungen zu den einzelnen Fällen transparent abgeben kann, ob er die richtige Basis für die Vergleichbarkeitsanalyse gewählt hat und somit die Anwendung des Fremdvergleichsgrundsatzes bei den von ihm im jeweiligen Besteuerungszeitraum getätigten abhängigen Transaktionen ausreichend nachweisen kann.</p><h3>Beginn und Bekanntgabe der Betriebsprüfung</h3><p>Gemäß der Bestimmung des § 44 der Steuerordnung beginnt eine Betriebsprüfung an dem vom Steuerverwalter festgelegten Tag, über den er den Steuerpflichtigen mittels einer Mitteilung informiert. Die Mitteilung muss auch den Ort der Prüfung, die Art der der Prüfung unterliegenden Steuer, den geprüften Zeitraum und die Frist zur Vorlage der geforderten Dokumentation zusammen mit einer Belehrung über die Folgen einer Nichteinhaltung enthalten. Der Steuerverwalter kann eine Betriebsprüfung auch ohne Mitteilung beginnen, wenn er den Verdacht hat, dass der Steuerpflichtige Unterlagen, die für die Beurteilung des Falles erforderlich sind, verändern oder vernichten wird.</p><p>Stellt der Steuerverwalter während einer laufenden Betriebsprüfung Unregelmäßigkeiten auch in anderen als den in der Mitteilung genannten Zeiträumen fest, ist er berechtigt, die Prüfung auch auf diese Zeiträume auszudehnen.</p><h3>Pflichten des Steuerpflichtigen während der Prüfung</h3><p>Der Steuerpflichtige ist verpflichtet, dem Steuerverwalter die Durchführung der Prüfung zu ermöglichen, Zugang zu Räumlichkeiten und seiner Software zu gewähren, zu kooperieren und ihm Unterlagen auch außerhalb seiner Räumlichkeiten zur Verfügung zu stellen, wenn der Steuerverwalter dies verlangt.</p><p>Während der Prüfung prüft der Steuerverwalter die eingereichten Unterlagen auf deren Richtigkeit, Vollständigkeit und Wahrheit. Stellt er Unregelmäßigkeiten fest, informiert er den Steuerpflichtigen darüber und bittet ihn um eine Erklärung. Der Steuerpflichtige kann beliebige Unterlagen vorlegen und Beweise sowie Erklärungen zum Fall abgeben, die der Steuerverwalter anschließend auswertet. Sind die Unterlagen oder Erklärungen unzureichend, bittet er um Ergänzung.</p><h2>Am häufigsten geprüfte Bereiche</h2><p>Hinsichtlich der geprüften Bereiche sind Dienstleistungen, Waren und immaterielle Vermögenswerte am häufigsten Gegenstand von Prüfungen. Darüber hinaus werden üblicherweise die Kostenverteilung zwischen verbundenen Personen und die Gruppenfinanzierung geprüft.</p><p>Die Prüfung selbst wird anhand von Stichproben durchgeführt, die vom Steuerverwalter ausgewählt werden und deren Vorlage er anschließend vom Steuerpflichtigen verlangt. Der Grund für die Auswahl einer bestimmten Stichprobe einer kontrollierten Transaktion kann deren Häufigkeit innerhalb der Gesamttätigkeit des Steuerpflichtigen sein. Die Auswahl der Stichprobe kann auch durch den Verdacht des Steuerverwalters beeinflusst werden, beispielsweise wenn der Steuerpflichtige sein Geschäftsmodell ändert oder im Jahresvergleich von Gewinn zu Verlust wechselt. Steuerverwalter eröffnen Betriebsprüfungen üblicherweise auch bei problematischen Steuerpflichtigen, beispielsweise bei solchen, bei denen es in der Vergangenheit bereits zu einer Steuernachforderung gekommen ist oder bei solchen, die risikoreiche Transaktionen durchführen.</p><h3>Was Steuerverwalter prüfen</h3><p>Bei einer Betriebsprüfung prüfen die Steuerverwalter insbesondere:</p><ul><li>ob der Gegenstand der Leistung tatsächlich erbracht wurde bzw. Dienstleistungen geliefert wurden,</li><li>ob das Unternehmen den Gegenstand der Leistung bzw. die gelieferten Dienstleistungen tatsächlich benötigt hat, d.h. der Steuerverwalter fragt, ob das geprüfte Unternehmen eine solche Dienstleistung auch bei einer unabhängigen Person beschafft hätte,</li><li>ob die Preise im Einklang mit dem Fremdvergleichsgrundsatz festgelegt wurden.</li></ul><h2>Am häufigsten identifizierte Probleme</h2><p>Zu den am häufigsten identifizierten Problemen bei Betriebsprüfungen gehören:</p><ul><li><strong>die Unfähigkeit des Unternehmens, die zwischen verbundenen Personen erbrachten Dienstleistungen angemessen zu erklären;</strong> der Steuerpflichtige muss zweifelsfrei nachweisen, dass die erbrachte Leistung gerechtfertigt war, d.h. mit den Bedürfnissen des Empfängers zusammenhängt und mit dem Fremdvergleichsgrundsatz im Einklang steht,</li><li><strong>unzureichende oder fehlende Verrechnungspreisdokumentation,</strong></li><li><strong>geringe Qualität der Verrechnungspreisdokumentation,</strong></li><li><strong>Unstimmigkeit des Inhalts der Dokumentation mit der Geschäftstätigkeit des Steuerpflichtigen und seinen Erklärungen,</strong></li><li><strong>unzureichende Begründung der Vergleichbarkeitsfaktoren,</strong> d.h. unzureichende Funktions- und Risikoanalyse, beispielsweise eine zu kleine oder falsch gewählte Vergleichsbasis,</li><li><strong>unzureichende Erklärung des niedrigeren Gewinnniveaus des Unternehmens im Vergleich zu anderen Unternehmen der Gruppe,</strong></li><li><strong>das Nichtvorhandensein von Verträgen und anderen Unterlagen, die das gewählte Vorgehen des Steuerpflichtigen stützen würden,</strong></li><li><strong>Unfähigkeit, dem Steuerverwalter die angeforderten Informationen über verbundene Personen zur Verfügung zu stellen,</strong></li><li><strong>Langsamkeit, Problematik oder Unfähigkeit des Steuerpflichtigen, auf verschiedene Anfragen des Steuerverwalters zu reagieren.</strong></li></ul><p>Ablauf und Ergebnis der Betriebsprüfung werden zweifellos durch die Herangehensweise des geprüften Steuerpflichtigen an das Thema Verrechnungspreise beeinflusst. Stellt der Steuerverwalter fest, dass der Steuerpflichtige im Dokumentationsprozess maximale Anstrengungen unternommen hat und sich diese Anstrengungen in der hohen Qualität der eingereichten Dokumentation niedergeschlagen haben, kann dies den Betriebsprüfungsprozess beschleunigen, beispielsweise durch die Genehmigung der verwendeten Methode, die Annahme der Erklärungen des Unternehmens ohne die Notwendigkeit einer tieferen Prüfung, was letztendlich dazu führt, dass keine zusätzliche Steuer festgesetzt wird.</p>',
        ARRAY['Verrechnungspreise', 'Betriebsprüfung', 'Dokumentation', 'Compliance'],
        TRUE
    );

    -- FR Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_1, 'fr', 
        'Contrôle fiscal et défauts les plus courants dans les prix de transfert',
        'Le but du contrôle fiscal est d''examiner les procédures du contribuable pour fixer les prix de transfert, c''est-à-dire s''il a choisi une méthode de transfert appropriée, s''il dispose d''une documentation suffisante pour les transactions examinées.',
        'Le déroulement général du contrôle fiscal est réglementé par les articles § 44 à § 47 de la loi n° 563/2009 Coll. sur l''administration fiscale (Code des impôts) et sur les modifications de certaines lois (ci-après « Code des impôts »). L''objectif du contrôle fiscal est d''examiner les procédures du contribuable lors de la fixation des prix de transfert, c''est-à-dire s''il a choisi une méthode de transfert appropriée, s''il dispose d''une documentation suffisante pour les transactions vérifiées, s''il peut fournir de manière transparente des explications pour les cas individuels, s''il a choisi la bonne base pour l''analyse de comparabilité et donc s''il peut démontrer suffisamment l''application du principe de pleine concurrence dans les transactions liées qu''il a effectuées au cours de la période fiscale donnée.',
        'Droit Fiscal', '8 min de lecture',
        '<h2>Objectif et déroulement du contrôle fiscal</h2><p>Le déroulement général du contrôle fiscal est réglementé par les articles § 44 à § 47 de la loi n° 563/2009 Coll. sur l''administration fiscale (Code des impôts) et sur les modifications de certaines lois (ci-après « Code des impôts »). L''objectif du contrôle fiscal est d''examiner les procédures du contribuable lors de la fixation des prix de transfert, c''est-à-dire s''il a choisi une méthode de transfert appropriée, s''il dispose d''une documentation suffisante pour les transactions vérifiées, s''il peut fournir de manière transparente des explications pour les cas individuels, s''il a choisi la bonne base pour l''analyse de comparabilité et donc s''il peut démontrer suffisamment l''application du principe de pleine concurrence dans les transactions liées qu''il a effectuées au cours de la période fiscale donnée.</p><h3>Début et notification du contrôle fiscal</h3><p>Selon l''article § 44 du Code des impôts, le contrôle fiscal commence le jour déterminé par l''administrateur fiscal et dont il informe le contribuable par le biais d''une notification. La notification doit également contenir le lieu du contrôle, le type d''impôt soumis au contrôle, la période contrôlée et le délai de soumission de la documentation requise ainsi que des instructions sur les conséquences du non-respect. L''administrateur fiscal peut commencer un contrôle fiscal sans notification s''il soupçonne que le contribuable modifiera ou détruira les documents nécessaires à l''évaluation du cas.</p><p>Si l''administrateur fiscal, au cours d''un contrôle fiscal en cours, identifie des écarts dans des périodes autres que celles mentionnées dans la notification, il est en droit d''étendre le contrôle à ces périodes également.</p><h3>Obligations du contribuable pendant le contrôle</h3><p>Le contribuable est tenu de permettre à l''administrateur fiscal d''effectuer le contrôle, de lui donner accès aux locaux et à ses logiciels, de coopérer et de lui prêter du matériel même en dehors de ses locaux si l''administrateur fiscal le demande.</p><p>Pendant le contrôle, l''administrateur fiscal examine les documents soumis du point de vue de leur exactitude, de leur exhaustivité et de leur véracité. S''il identifie des écarts, il en informe le contribuable et lui demande des explications. Le contribuable peut soumettre tous les documents et fournir des preuves et des explications sur le cas, que l''administrateur fiscal évalue ensuite. Si les documents ou les explications sont insuffisants, il demande un complément.</p><h2>Domaines les plus fréquemment contrôlés</h2><p>Du point de vue des domaines contrôlés, l''objet le plus fréquent des contrôles est le domaine des services, des biens et des actifs incorporels. De plus, la répartition des coûts entre les entreprises liées et le financement du groupe sont couramment examinés.</p><p>Le contrôle lui-même est effectué au moyen d''échantillons sélectionnés par l''administrateur fiscal, qui demande ensuite leur soumission au contribuable. La raison du choix d''un échantillon de transaction contrôlée particulier peut être sa fréquence au sein de l''activité globale du contribuable. La sélection de l''échantillon peut également être influencée par les soupçons de l''administrateur fiscal, par exemple, si le contribuable change de modèle commercial ou passe d''un bénéfice à une perte d''une année sur l''autre. Les administrateurs fiscaux ouvrent également généralement des contrôles fiscaux pour les contribuables problématiques, par exemple ceux qui ont déjà fait l''objet d''un redressement ou ceux qui effectuent des transactions à risque.</p><h3>Ce que les administrateurs fiscaux contrôlent</h3><p>Lors d''un contrôle fiscal, les administrateurs fiscaux examinent principalement :</p><ul><li>si l''objet de la prestation a été effectivement livré ou les services fournis,</li><li>si l''entreprise avait réellement besoin de l''objet de la prestation ou des services fournis, c''est-à-dire que l''administrateur fiscal se demande si l''entité contrôlée fournirait un tel service à une personne indépendante,</li><li>si les prix ont été fixés conformément au principe de pleine concurrence.</li></ul><h2>Problèmes les plus fréquemment identifiés</h2><p>Les problèmes les plus fréquemment identifiés lors des contrôles fiscaux comprennent :</p><ul><li><strong>l''incapacité de l''entreprise à expliquer de manière adéquate les services fournis entre personnes liées ;</strong> le contribuable doit indubitablement prouver que le service fourni était justifié, c''est-à-dire qu''il est lié aux besoins du bénéficiaire et est conforme au principe de pleine concurrence,</li><li><strong>une documentation de transfert insuffisante ou inexistante,</strong></li><li><strong>une mauvaise qualité de la documentation de transfert,</strong></li><li><strong>une incohérence entre le contenu de la documentation et l''activité commerciale du contribuable et ses explications,</strong></li><li><strong>une justification insuffisante des facteurs de comparabilité,</strong> c''est-à-dire une analyse fonctionnelle et des risques inadéquate, par exemple une base comparative trop petite ou mal choisie,</li><li><strong>une explication insuffisante du niveau de bénéfice inférieur de l''entreprise par rapport aux autres entreprises du groupe,</strong></li><li><strong>l''inexistence de contrats et d''autres documents qui étayeraient la démarche choisie par le contribuable,</strong></li><li><strong>l''incapacité de fournir les informations demandées sur les personnes liées à l''administrateur fiscal,</strong></li><li><strong>la lenteur, le caractère problématique ou l''incapacité du contribuable à répondre aux diverses demandes de l''administrateur fiscal.</strong></li></ul><p>Le déroulement et le résultat du contrôle fiscal sont indubitablement influencés par l''approche du contribuable contrôlé à l''égard de la problématique des prix de transfert. Si l''administrateur fiscal constate que le contribuable a fait un effort maximal dans le processus de documentation et que cet effort s''est traduit par une documentation soumise de haute qualité, cela peut accélérer le processus de contrôle fiscal, par exemple en approuvant la méthode utilisée, en acceptant les explications de l''entreprise sans avoir besoin d''un examen plus approfondi, ce qui aboutit finalement à ne pas imposer d''impôt supplémentaire.</p>',
        ARRAY['prix de transfert', 'contrôle fiscal', 'documentation', 'conformité'],
        TRUE
    );

    -- 2. Vybraná judikatúra v oblasti transferového oceňovania
    INSERT INTO public.legis_blogs (site_id, slug, image_url, is_published, created_at)
    VALUES (v_site_id, 'judikatura-transfer-pricing', '/sources/images/litigation-1.jpg', TRUE, '2024-11-10 10:00:00+00')
    RETURNING id INTO v_blog_id_2;

    -- SK Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_2, 'sk', 
        'Vybraná judikatúra v oblasti transferového oceňovania',
        'Problematika transferového oceňovania je dynamicky sa vyvíjajúcou oblasťou a možno povedať, že jej právna úprava nie je dostatočná a jasná, čo sa prejavuje aj v rôznych pohľadoch správcu dane a daňovníka.',
        'Problematika transferového oceňovania je dynamicky sa vyvíjajúcou oblasťou a možno povedať, že jej právna úprava nie je dostatočná a jasná, čo sa prejavuje aj v rôznych pohľadoch z hľadiska správcu dane a daňovníka. V praxi to potom častokrát končí dorubením dane daňovníkovi a následnými súdnymi spormi. Pre potreby tohto článku sa zameriame na rôzne pohľady na použitú transferovú metódu, záväznosť smerníc o transferovom oceňovaní (ďalej len „smernica“) a na dôkazné bremeno.',
        'Judikatúra', '12 min čítania',
        '<h2>Úvod do problematiky</h2><p>Problematika transferového oceňovania je dynamicky sa vyvíjajúcou oblasťou a možno povedať, že jej právna úprava nie je dostatočná a jasná, čo sa prejavuje aj v rôznych pohľadoch z hľadiska správcu dane a daňovníka. V praxi to potom častokrát končí dorubením dane daňovníkovi a následnými súdnymi spormi. Pre potreby tohto článku sa zameriame na rôzne pohľady na použitú transferovú metódu, záväznosť smerníc o transferovom oceňovaní (ďalej len „smernica“) a na dôkazné bremeno.</p><h2>Rozsudok Krajského súdu v Bratislave – IKEA Industry Slovakia</h2><p>Krajský súd v Bratislave svojím rozsudkom zapísaným pod číslom konania 1S/231/2016 zamietol žalobu spoločnosti IKEA Industry Slovakia (ďalej len „žalobca“) proti Finančnému riaditeľstvu SR (ďalej len „žalovaný“). Žalovaný vykonal u žalobcu daňovú kontrolu, na základe ktorej dorubil žalobcovi daň. Dôvodom dorubenia dane bolo zistenie, že žalobcom použitá metóda nezávislej trhovej ceny sa nemala použiť, pretože žalobca nevedel preukázať dostatočnú vzorku porovnateľných nezávislých transakcií, produktov a ich cien, čím nebola naplnená podmienka porovnateľnosti produktu, ekonomických okolností, zmluvných podmienok, funkcií a rizík. Žalovaný vzhľadom na nepreukázanie vzorky použil metódu čistého obchodného rozpätia, výsledkom čoho bol daňový nedoplatok žalobcu. Svoje závery odôvodnil s použitím príslušných ustanovení zákona o dani z príjmov s tým, že ich oprel o smernicu.</p><h3>Argumenty žalobcu</h3><p>Žalobca naopak namietal, že úplne porovnateľné podmienky vzhľadom na rôzne objemy výroby, premenlivé výrobné podmienky a ďalšie faktory, akými sú napríklad dotácie, nie je možné dosiahnuť. Taktiež namietal, že smernica je na území SR neúčinná, nemá záväzný charakter, pretože nebola uverejnená v Zbierke zákonov SR a že je povinnosťou správcu dane dokázať, že ceny použité žalobcom nie sú v súlade s cenami na nezávislom trhu.</p><h3>Rozhodnutie súdu</h3><p>Súd vo svojom rozhodnutí konštatoval, že ak žalobca použil metódu nezávislej trhovej ceny, musí byť schopný preukázať vzorku porovnateľných nezávislých transakcií. Zároveň akceptoval smernicu ako všeobecne uznávaný doplňujúci výkladový nástroj k všeobecne záväzným právnym predpisom. Podľa súdu dôkazné bremeno je na žalobcovi, ktorý je povinný preukázať všetky skutočnosti, ktoré majú vplyv na správne určenie dane.</p><h2>Záväznosť smernice OECD</h2><p>Pokiaľ ide o smernicu, túto zaraďujeme medzi tzv. mäkké právo (soft law). Hoci ide o najucelenejší dokument upravujúci problematiku transferového oceňovania, nemá záväznú silu. Jej funkcia je skôr odporúčacia. Smernica je výkladovým nástrojom k článku 9 Modelovej zmluvy OECD o zamedzení dvojitého zdanenia. Význam môže mať ako podporný nástroj v argumentácii pre otázky metodického uplatnenia výberu transferovej metodiky a politiky daňovníka na jednej strane a pre účely daňovej kontroly na druhej strane. V rámci právneho poriadku SR ju však nemôžeme považovať ani za nástroj výkladu zákonných ustanovení o transferovom oceňovaní pri transakciách spravujúcich sa slovenským právom. Preto podľa nášho názoru smernica nemá v slovenskom právnom poriadku záväzný charakter.</p><h2>Dôkazné bremeno v transferovom oceňovaní</h2><p>K otázke dôkazného bremena z hľadiska subjektu, ktorý ho nesie, existuje takisto viacero rozhodnutí Najvyššieho súdu SR. V rozsudku č. 5Sžf/97/2009 súd konštatuje, že žalobca ako daňový subjekt nemusí preukazovať svoje tvrdenie, ktoré sám uvádza v rôznych daňových dokladoch, podaniach a vyhláseniach, ak nenastane opak, t. j. ak správca dane pri daňovej kontrole alebo v daňovom konaní nepredostrie daňovému subjektu jasné závery dokazujúce pochybnosti o jeho tvrdeniach.</p><p>V inom rozhodnutí pod č. 2Sžf/8/2016 súd upozorňuje na to, že dôkazné bremeno daňového subjektu nie je absolútne. Na jednej strane treba mať na pamäti, že dokazovanie vykonáva správca dane a na druhej strane treba takisto prihliadať na skutočnosti, ktoré je povinný preukázať samotný daňový subjekt.</p><h2>Záver</h2><p>Na základe vyššie uvedeného by sa dalo uzavrieť, že je povinnosťou daňového subjektu preukázať všetky skutočnosti, ktoré mali vplyv na ním určenú výšku dane a spôsob, akým k nej dospel. Táto požiadavka nie je naplnená v prípade, ak z dokumentácie daňovníka nevyplýva jasná odpoveď na jeho transferovú politiku. Je však prirodzené, že správca dane môže mať otázky a môže od daňovníka žiadať doplňujúce informácie. V takom prípade je povinnosťou daňovníka na tieto otázky odpovedať a informácie doplniť.</p>',
        ARRAY['judikatúra', 'transferové oceňovanie', 'súdne rozhodnutia', 'OECD smernica'],
        TRUE
    );

    -- EN Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_2, 'en', 
        'Selected case law in the field of transfer pricing',
        'The issue of transfer pricing is a dynamically developing area and it can be said that its legal regulation is not sufficient and clear, which is also reflected in different views of the tax administrator and the taxpayer.',
        'The issue of transfer pricing is a dynamically developing area and it can be said that its legal regulation is not sufficient and clear, which is also reflected in different views from the perspective of the tax administrator and the taxpayer. In practice, this often ends with a tax reassessment for the taxpayer and subsequent legal disputes. For the purposes of this article, we will focus on different views on the transfer method used, the binding nature of the transfer pricing guidelines (hereinafter "the guideline") and the burden of proof.',
        'Case Law', '12 min read',
        '<h2>Introduction to the issue</h2><p>The issue of transfer pricing is a dynamically developing area and it can be said that its legal regulation is not sufficient and clear, which is also reflected in different views from the perspective of the tax administrator and the taxpayer. In practice, this often ends with a tax reassessment for the taxpayer and subsequent legal disputes. For the purposes of this article, we will focus on different views on the transfer method used, the binding nature of the transfer pricing guidelines (hereinafter "the guideline") and the burden of proof.</p><h2>Judgment of the Regional Court in Bratislava - IKEA Industry Slovakia</h2><p>The Regional Court in Bratislava, by its judgment registered under case number 1S/231/2016, dismissed the lawsuit of IKEA Industry Slovakia (hereinafter "the plaintiff") against the Financial Directorate of the SR (hereinafter "the defendant"). The defendant performed a tax audit at the plaintiff, on the basis of which they reassessed the plaintiff''s tax. The reason for the tax reassessment was the finding that the arm''s length method used by the plaintiff should not have been used because the plaintiff could not demonstrate a sufficient sample of comparable independent transactions, products and their prices, thus failing to meet the condition of comparability of the product, economic circumstances, contractual terms, functions and risks. The defendant, given the failure to prove the sample, used the transactional net margin method, which resulted in a tax arrears for the plaintiff. They justified their conclusions by applying the relevant provisions of the Income Tax Act, supporting them with the guideline.</p><h3>Plaintiff''s arguments</h3><p>On the other hand, the plaintiff objected that completely comparable conditions cannot be achieved given the different production volumes, variable production conditions and other factors such as subsidies. They also objected that the guideline is ineffective in the territory of the SR, does not have a binding character because it was not published in the Collection of Laws of the SR, and that it is the obligation of the tax administrator to prove that the prices used by the plaintiff are not in accordance with the prices on the independent market.</p><h3>Court decision</h3><p>In its decision, the court stated that if the plaintiff used the arm''s length method, they must be able to prove a sample of comparable independent transactions. At the same time, it accepted the guideline as a generally recognized supplementary interpretative tool to generally binding legal regulations. According to the court, the burden of proof is on the plaintiff, who is obliged to prove all facts that have an influence on the correct determination of tax.</p><h2>Binding nature of the OECD Guideline</h2><p>Regarding the guideline, we classify it among the so-called soft law. Although it is the most comprehensive document governing the issue of transfer pricing, it does not have binding force. Its function is rather recommendatory. The guideline is an interpretative tool for Article 9 of the OECD Model Tax Convention on the avoidance of double taxation. It can be important as a supporting tool in argumentation for issues of methodological application of the choice of transfer methodology and the taxpayer''s policy on the one hand and for the purposes of tax audit on the other. However, within the legal system of the SR, we cannot even consider it as a tool for interpreting the legal provisions on transfer pricing for transactions governed by Slovak law. Therefore, in our opinion, the guideline does not have a binding character in the Slovak legal system.</p><h2>Burden of proof in transfer pricing</h2><p>Regarding the issue of the burden of proof from the perspective of the entity that bears it, there are also several decisions of the Supreme Court of the SR. In judgment no. 5Sžf/97/2009, the court states that the plaintiff as a tax entity does not have to prove their statement, which they themselves state in various tax documents, submissions and declarations, unless the opposite happens, i.e. if the tax administrator during the tax audit or in the tax procedure does not present clear conclusions to the tax entity proving doubts about their statements.</p><p>In another decision under no. 2Sžf/8/2016, the court draws attention to the fact that the tax entity''s burden of proof is not absolute. On the one hand, it must be remembered that the proof is carried out by the tax administrator, and on the other hand, it must also take into account facts that the tax entity itself is obliged to prove.</p><h2>Conclusion</h2><p>Based on the above, it could be concluded that it is the obligation of the tax entity to prove all facts that influenced the amount of tax determined by them and the way they reached it. This requirement is not met if the taxpayer''s documentation does not provide a clear answer to their transfer policy. However, it is natural that the tax administrator may have questions and may request additional information from the taxpayer. In this case, it is the taxpayer''s obligation to answer these questions and supplement the information.</p>',
        ARRAY['case law', 'transfer pricing', 'court decisions', 'OECD guideline'],
        TRUE
    );

    -- DE Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_2, 'de', 
        'Ausgewählte Rechtsprechung im Bereich der Verrechnungspreisgestaltung',
        'Das Thema Verrechnungspreisgestaltung ist ein sich dynamisch entwickelnder Bereich, und man kann sagen, dass seine rechtliche Regelung nicht ausreichend und klar ist, was sich auch in unterschiedlichen Ansichten des Steuerverwalters und des Steuerpflichtigen widerspiegelt.',
        'Das Thema Verrechnungspreisgestaltung ist ein sich dynamisch entwickelnder Bereich, und man kann sagen, dass seine rechtliche Regelung nicht ausreichend und klar ist, was sich auch in unterschiedlichen Ansichten aus der Sicht des Steuerverwalters und des Steuerpflichtigen widerspiegelt. In der Praxis endet dies dann oft mit einer Steuernachforderung für den Steuerpflichtigen und anschließenden Rechtsstreitigkeiten. Für die Zwecke dieses Artikels werden wir uns auf unterschiedliche Sichtweisen auf die verwendete Verrechnungsmethode, die Verbindlichkeit der Verrechnungspreisrichtlinien (im Folgenden „die Richtlinie“) und die Beweislast konzentrieren.',
        'Rechtsprechung', '12 min Lesezeit',
        '<h2>Einführung in das Thema</h2><p>Das Thema Verrechnungspreisgestaltung ist ein sich dynamisch entwickelnder Bereich, und man kann sagen, dass seine rechtliche Regelung nicht ausreichend und klar ist, was sich auch in unterschiedlichen Ansichten aus der Sicht des Steuerverwalters und des Steuerpflichtigen widerspiegelt. In der Praxis endet dies dann oft mit einer Steuernachforderung für den Steuerpflichtigen und anschließenden Rechtsstreitigkeiten. Für die Zwecke dieses Artikels werden wir uns auf unterschiedliche Sichtweisen auf die verwendete Verrechnungsmethode, die Verbindlichkeit der Verrechnungspreisrichtlinien (im Folgenden „die Richtlinie“) und die Beweislast konzentrieren.</p><h2>Urteil des Bezirksgerichts in Bratislava - IKEA Industry Slovakia</h2><p>Das Bezirksgericht in Bratislava hat mit seinem unter der Geschäftsnummer 1S/231/2016 eingetragenen Urteil die Klage der Gesellschaft IKEA Industry Slovakia (im Folgenden „die Klägerin“) gegen die Finanzdirektion der SR (im Folgenden „die Beklagte“) abgewiesen. Die Beklagte führte bei der Klägerin eine Betriebsprüfung durch, auf deren Grundlage sie der Klägerin Steuern nachforderte. Grund für die Steuernachforderung war die Feststellung, dass die von der Klägerin angewandte Preisvergleichsmethode nicht hätte angewendet werden dürfen, da die Klägerin keine ausreichende Stichprobe vergleichbarer unabhängiger Transaktionen, Produkte und deren Preise nachweisen konnte, wodurch die Bedingung der Vergleichbarkeit des Produkts, der wirtschaftlichen Umstände, der vertraglichen Bedingungen, der Funktionen und der Risiken nicht erfüllt war. Die Beklagte wandte angesichts des fehlenden Nachweises der Stichprobe die geschäftsvorfallbezogene Nettomargenmethode an, was zu einem Steuerrückstand der Klägerin führte. Sie begründete ihre Schlussfolgerungen unter Anwendung der einschlägigen Bestimmungen des Einkommensteuergesetzes und stützte diese auf die Richtlinie.</p><h3>Argumente der Klägerin</h3><p>Die Klägerin wandte hingegen ein, dass vollkommen vergleichbare Bedingungen angesichts unterschiedlicher Produktionsmengen, variabler Produktionsbedingungen und anderer Faktoren wie beispielsweise Subventionen nicht erreicht werden können. Sie wandte ferner ein, dass die Richtlinie im Gebiet der SR unwirksam sei, keinen verbindlichen Charakter habe, da sie nicht in der Gesetzessammlung der SR veröffentlicht worden sei, und dass es Aufgabe des Steuerverwalters sei, nachzuweisen, dass die von der Klägerin verwendeten Preise nicht mit den Preisen auf dem unabhängigen Markt übereinstimmen.</p><h3>Gerichtsentscheidung</h3><p>Das Gericht stellte in seiner Entscheidung fest, dass die Klägerin, wenn sie die Preisvergleichsmethode angewendet hat, in der Lage sein muss, eine Stichprobe vergleichbarer unabhängiger Transaktionen nachzuweisen. Gleichzeitig akzeptierte es die Richtlinie als allgemein anerkanntes ergänzendes Auslegungsinstrument zu allgemein verbindlichen Rechtsvorschriften. Nach Ansicht des Gerichts liegt die Beweislast bei der Klägerin, die verpflichtet ist, alle Tatsachen nachzuweisen, die Einfluss auf die richtige Festsetzung der Steuer haben.</p><h2>Verbindlichkeit der OECD-Richtlinie</h2><p>Was die Richtlinie betrifft, so ordnen wir diese dem sogenannten Soft Law zu. Obwohl es sich um das umfassendste Dokument zur Regelung der Verrechnungspreisproblematik handelt, hat es keine verbindliche Kraft. Seine Funktion ist eher empfehlend. Die Richtlinie ist ein Auslegungsinstrument zu Artikel 9 des OECD-Musterabkommens zur Vermeidung der Doppelbesteuerung. Sie kann einerseits als unterstützendes Instrument in der Argumentation für Fragen der methodischen Anwendung der Wahl der Verrechnungsmethode und der Politik des Steuerpflichtigen und andererseits für Zwecke der Betriebsprüfung von Bedeutung sein. Im Rahmen der Rechtsordnung der SR können wir sie jedoch nicht einmal als Instrument zur Auslegung der gesetzlichen Bestimmungen über Verrechnungspreise bei Transaktionen betrachten, die dem slowakischen Recht unterliegen. Daher hat die Richtlinie unserer Meinung nach in der slowakischen Rechtsordnung keinen verbindlichen Charakter.</p><h2>Beweislast bei Verrechnungspreisen</h2><p>Zur Frage der Beweislast aus der Sicht des Rechtsträgers, der sie trägt, gibt es ebenfalls mehrere Entscheidungen des Obersten Gerichtshofs der SR. Im Urteil Nr. 5Sžf/97/2009 stellt das Gericht fest, dass die Klägerin als Steuerpflichtige ihre Behauptung, die sie selbst in verschiedenen Steuerunterlagen, Eingaben und Erklärungen aufstellt, nicht beweisen muss, es sei denn, das Gegenteil tritt ein, d. h. wenn der Steuerverwalter bei der Betriebsprüfung oder im Steuerverfahren der Steuerpflichtigen keine klaren Schlussfolgerungen vorlegt, die Zweifel an ihren Behauptungen belegen.</p><p>In einer anderen Entscheidung unter der Nr. 2Sžf/8/2016 weist das Gericht darauf hin, dass die Beweislast des Steuerpflichtigen nicht absolut ist. Einerseits ist zu bedenken, dass die Beweisführung durch den Steuerverwalter erfolgt, und andererseits sind auch Tatsachen zu berücksichtigen, die der Steuerpflichtige selbst zu beweisen verpflichtet ist.</p><h2>Fazit</h2><p>Basierend auf dem Vorstehenden ließe sich schlussfolgern, dass der Steuerpflichtige verpflichtet ist, alle Tatsachen nachzuweisen, die Einfluss auf die von ihm festgesetzte Steuerhöhe und die Art und Weise, wie er zu dieser gelangt ist, hatten. Diese Anforderung ist nicht erfüllt, wenn aus der Dokumentation des Steuerpflichtigen keine klare Antwort auf seine Verrechnungspreispolitik hervorgeht. Es ist jedoch natürlich, dass der Steuerverwalter Fragen haben und vom Steuerpflichtigen ergänzende Informationen anfordern kann. In diesem Fall ist der Steuerpflichtige verpflichtet, diese Fragen zu beantworten und die Informationen zu ergänzen.</p>',
        ARRAY['Rechtsprechung', 'Verrechnungspreise', 'Gerichtsentscheidungen', 'OECD-Richtlinie'],
        TRUE
    );

    -- FR Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_2, 'fr', 
        'Jurisprudence sélectionnée en matière de prix de transfert',
        'La problématique des prix de transfert est un domaine en évolution dynamique et on peut dire que sa réglementation juridique n''est pas suffisante et claire, ce qui se manifeste également par des points de vue différents de l''administration fiscale et du contribuable.',
        'La problématique des prix de transfert est un domaine en évolution dynamique et on peut dire que sa réglementation juridique n''est pas suffisante et claire, ce qui se manifeste également par des points de vue différents du point de vue de l''administrateur fiscal et du contribuable. En pratique, cela aboutit souvent à des redressements fiscaux pour le contribuable et à des litiges judiciaires ultérieurs. Pour les besoins de cet article, nous nous concentrerons sur les différentes perspectives concernant la méthode de transfert utilisée, la force obligatoire des directives sur les prix de transfert (ci-après « la directive ») et la charge de la preuve.',
        'Jurisprudence', '12 min de lecture',
        '<h2>Introduction à la problématique</h2><p>La problématique des prix de transfert est un domaine en évolution dynamique et on peut dire que sa réglementation juridique n''est pas suffisante et claire, ce qui se manifeste également par des points de vue différents du point de vue de l''administrateur fiscal et du contribuable. En pratique, cela aboutit souvent à des redressements fiscaux pour le contribuable et à des litiges judiciaires ultérieurs. Pour les besoins de cet article, nous nous concentrerons sur les différentes perspectives concernant la méthode de transfert utilisée, la force obligatoire des directives sur les prix de transfert (ci-après « la directive ») et la charge de la preuve.</p><h2>Arrêt du Tribunal régional de Bratislava - IKEA Industry Slovakia</h2><p>Le Tribunal régional de Bratislava, par son arrêt enregistré sous le numéro de dossier 1S/231/2016, a rejeté la plainte de la société IKEA Industry Slovakia (ci-après « le plaignant ») contre la Direction financière de la République slovaque (ci-après « le défendeur »). Le défendeur a effectué un contrôle fiscal chez le plaignant, sur la base duquel il a imposé un impôt supplémentaire au plaignant. La raison du redressement fiscal était la constatation que la méthode du prix comparable sur le marché libre utilisée par le plaignant n''aurait pas dû être appliquée, car le plaignant ne pouvait pas démontrer un échantillon suffisant de transactions indépendantes comparables, de produits et de leurs prix, ne remplissant ainsi pas la condition de comparabilité du produit, des circonstances économiques, des conditions contractuelles, des fonctions et des risques. Le défendeur, étant donné que l''échantillon n''a pas été prouvé, a utilisé la méthode de la marge nette transactionnelle, ce qui a entraîné un arriéré d''impôt pour le plaignant. Il a justifié ses conclusions en appliquant les dispositions pertinentes de la loi sur l''impôt sur le revenu, en les appuyant sur la directive.</p><h3>Arguments du plaignant</h3><p>D''autre part, le plaignant a objecté que des conditions totalement comparables ne peuvent être atteintes compte tenu des différents volumes de production, des conditions de production variables et d''autres facteurs tels que les subventions. Il a également objecté que la directive est inefficace sur le territoire de la République slovaque, n''a pas de caractère contraignant car elle n''a pas été publiée au Journal officiel de la République slovaque, et qu''il est de l''obligation de l''administrateur fiscal de prouver que les prix utilisés par le plaignant ne sont pas conformes aux prix sur le marché indépendant.</p><h3>Décision du tribunal</h3><p>Dans sa décision, le tribunal a déclaré que si le plaignant a utilisé la méthode du prix comparable sur le marché libre, il doit être en mesure de prouver un échantillon de transactions indépendantes comparables. En même temps, il a accepté la directive comme un outil d''interprétation complémentaire généralement reconnu à la réglementation juridique généralement contraignante. Selon le tribunal, la charge de la preuve incombe au plaignant, qui est tenu de prouver tous les faits qui ont une incidence sur la détermination correcte de l''impôt.</p><h2>Force obligatoire de la directive de l''OCDE</h2><p>En ce qui concerne la directive, nous la classons parmi ce qu''on appelle le droit souple (soft law). Bien qu''il s''agisse du document le plus complet régissant la problématique des prix de transfert, il n''a pas de force obligatoire. Sa fonction est plutôt de recommandation. La directive est un outil d''interprétation de l''article 9 de la Convention modèle de l''OCDE en matière de double imposition. Elle peut avoir de l''importance en tant qu''outil de soutien dans l''argumentation pour les questions d''application méthodologique du choix de la méthodologie de transfert et de la politique du contribuable d''une part et aux fins du contrôle fiscal d''autre part. Cependant, dans le cadre de l''ordre juridique de la République slovaque, nous ne pouvons même pas la considérer comme un outil d''interprétation des dispositions légales sur les prix de transfert pour les transactions régies par le droit slovaque. Par conséquent, à notre avis, la directive n''a pas de caractère contraignant dans l''ordre juridique slovaque.</p><h2>Charge de la preuve en matière de prix de transfert</h2><p>Plusieurs décisions de la Cour suprême de la République slovaque existent également sur la question de la charge de la preuve du point de vue de l''entité qui la supporte. Dans l''arrêt n° 5Sžf/97/2009, le tribunal déclare que le plaignant en tant qu''entité fiscale n''a pas à prouver son affirmation, qu''il énonce lui-même dans divers documents fiscaux, soumissions et déclarations, à moins que le contraire ne se produise, c''est-à-dire si l''administrateur fiscal lors du contrôle fiscal ou dans la procédure fiscale ne présente pas à l''entité fiscale des conclusions claires prouvant des doutes sur ses affirmations.</p><p>Dans une autre décision sous le n° 2Sžf/8/2016, le tribunal attire l''attention sur le fait que la charge de la preuve de l''entité fiscale n''est pas absolue. D''une part, il faut se rappeler que la preuve est menée par l''administrateur fiscal, et d''autre part, il faut également tenir compte des faits que l''entité fiscale elle-même est tenue de prouver.</p><h2>Conclusion</h2><p>Sur la base de ce qui précède, on pourrait conclure qu''il est de l''obligation de l''entité fiscale de prouver tous les faits qui ont influencé le montant de l''impôt déterminé par elle et la manière dont elle y est parvenue. Cette exigence n''est pas satisfaite si la documentation du contribuable ne fournit pas de réponse claire à sa politique de prix de transfert. Cependant, il est naturel que l''administrateur fiscal puisse avoir des questions et puisse demander des informations supplémentaires au contribuable. Dans ce cas, il est de l''obligation du contribuable de répondre à ces questions et de compléter les informations.</p>',
        ARRAY['jurisprudence', 'prix de transfert', 'décisions de justice', 'directives OCDE'],
        TRUE
    );

    -- 3. Kedy je možné započítať pohľadávky
    INSERT INTO public.legis_blogs (site_id, slug, image_url, is_published, created_at)
    VALUES (v_site_id, 'zapocitanie-pohladavok', '/sources/images/debt-collection-1.jpg', TRUE, '2024-11-05 10:00:00+00')
