    -- SK Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_3, 'sk', 
        'Kedy je možné započítať pohľadávky',
        'Zánik pohľadávok započítaním predstavuje formu bezhotovostného vyrovnania medzi dlžníkom a veriteľom, kedy medzi nimi nedochádza k reálnemu plneniu, čo nepochybne prináša úsporu nákladov.',
        'Zánik pohľadávok započítaním predstavuje formu bezhotovostného vyrovnania medzi dlžníkom a veriteľom, kedy medzi nimi nedochádza k reálnemu plneniu, čo nepochybne prináša úsporu nákladov, ktoré by tieto strany inak museli vynaložiť. Dalo by sa povedať, že ide o formu náhradného splnenia záväzku voči veriteľovi, ktorým sa jeho pohľadávka uspokojí. Vzhľadom na relatívnu jednoduchosť a efektívnosť splnenia záväzkov týmto spôsobom, ide o v praxi často využívaný inštitút. Zákonné podmienky jeho využitia však nie sú vždy dodržané.',
        'Obchodné právo', '10 min čítania',
        '<h2>Úvod do problematiky započítania</h2><p>Zánik pohľadávok započítaním predstavuje formu bezhotovostného vyrovnania medzi dlžníkom a veriteľom, kedy medzi nimi nedochádza k reálnemu plneniu, čo nepochybne prináša úsporu nákladov, ktoré by tieto strany inak museli vynaložiť. Dalo by sa povedať, že ide o formu náhradného splnenia záväzku voči veriteľovi, ktorým sa jeho pohľadávka uspokojí. Vzhľadom na relatívnu jednoduchosť a efektívnosť splnenia záväzkov týmto spôsobom, ide o v praxi často využívaný inštitút. Zákonné podmienky jeho využitia však nie sú vždy dodržané.</p><h2>Hmotnoprávne podmienky pre započítanie</h2><p>Základným predpokladom splnenia záväzku započítaním je dodržanie hmotnoprávnych podmienok. Tieto podmienky môžeme rozdeliť na všeobecné a osobitné. Všeobecné podmienky započítateľnosti sú:</p><ul><li>vzájomnosť pohľadávok</li><li>rovnaký druh plnenia</li><li>spôsobilosť na započítanie</li><li>strany urobili určitý prejav vôle smerujúci k zániku pohľadávok započítaním.</li></ul><p>Vyššie uvedené všeobecné podmienky započítateľnosti vyplývajú z ustanovení § 580 a § 581 Občianskeho zákonníka. Tieto sú modifikované ustanoveniami § 358 až § 364 Obchodného zákonníka prípadne inými relevantnými právnymi predpismi.</p><h3>Vzájomnosť pohľadávok</h3><p>O vzájomnosti pohľadávok hovoríme vtedy, ak medzi tými istými stranami je každá strana zároveň veriteľom aj dlžníkom. Podmienka vzájomnosti pohľadávky musí byť splnená bez ohľadu na to, či ide o jednostranné započítanie alebo dohodu o započítaní. Zákon ustanovuje výnimky z podmienky vzájomnosti, ktorými upravuje prípady, kedy došlo k zmene v osobe veriteľa, napríklad z dôvodu postúpenia pohľadávky. V takom prípade si dlžník môže započítať voči postupníkovi (novému veriteľovi) tie pohľadávky, ktoré mal voči postupcovi v čase, keď sa o postúpení pohľadávky od postupcu postupníkovi dozvedel.</p><h3>Rovnaký druh plnenia</h3><p>Ďalšou zákonnou podmienkou je, že pohľadávky musia byť rovnakého druhu, t. j. ich obsahom je plnenie rovnaké čo do množstva a druhu. Z hľadiska druhu môže ísť o peňažné pohľadávky, kedy je ich výška vyjadrená v peniazoch alebo o nepeňažné pohľadávky, kedy ich výška je vyjadrená v iných jednotkách, napríklad v kilogramoch. Najčastejšie pôjde o pohľadávky peňažného plnenia a v obchodných záväzkových vzťahoch nebráni započítaniu ani to, ak sú pohľadávky v rôznych menách, ak sú tieto meny voľne zameniteľné.</p><h3>Spôsobilosť na započítanie</h3><p>Pohľadávky sú spôsobilé na započítanie vtedy, ak započítanie nie je vylúčené zákonom alebo dohodou účastníkov. Dohoda účastníkov o nemožnosti započítať vzájomné pohľadávky predstavuje zákonnú prekážku. Občiansky zákonník v ustanovení § 581 ods. 1 a ods. 2 upravuje vylúčenia z jednostranného započítania. Podľa § 581 ods. 1 je jednostranné započítanie neprípustné proti pohľadávke na náhradu škody na zdraví, ak nejde o vzájomnú pohľadávku na náhradu škody toho istého druhu.</p><h2>Formy započítania</h2><p>K samotnému započítaniu môže dôjsť jednostranným úkonom alebo dohodou strán. Pri jednostrannom započítaní musia byť splnené všetky uvedené podmienky.</p><h3>Jednostranné započítanie</h3><p>Jednostranné započítanie je voči druhej strane účinné od okamihu, kedy sa dostalo do jeho dispozície. Naopak v prípade dohody strán je táto dohoda účinná od okamihu účinnosti prijatia návrhu druhou stranou, napríklad dohoda nadobúda účinnosť podpisom účastníkov. Reálne účinky započítania sa však nespájajú s okamihom doručenia oznámenia o jednostrannom započítaní alebo uzavretím dohody, ale s okamihom stretnutia pohľadávok, t. j. okamihom, kedy sa neskoršia z nich stala splatnou.</p><h3>Dohoda o započítaní</h3><p>Dohoda o započítaní pohľadávok musí byť podpísaná osobami oprávnenými konať za spoločnosť. Môže ísť napríklad o štatutárov spoločností, prípadne osoby na to splnomocnené, napríklad o povereného zamestnanca, čo vyplýva z pracovnej náplne alebo vnútorných organizačných dokumentov.</p><h2>Osobitné prípady započítania</h2><p>Pohľadávku je možné započítať aj počas prebiehajúceho súdneho konania alebo exekučného konania. Samotná existencia prebiehajúceho konania nemá na započítateľnosť pohľadávky žiaden vplyv. Dôležité je, aby pohľadávky boli spôsobilé na započítanie v momente, kedy sa stretli, a to aj v prípade, ak by jedna z pohľadávok nebola neskôr súdom priznaná.</p><p>V prípade pasívnych solidárnych záväzkov, kedy na strane dlžníka vystupuje viacero subjektov a veriteľ je oprávnený uplatniť svoju pohľadávku na plnenie u ktoréhokoľvek z nich, si môže ktorýkoľvek z dlžníkov započítať svoju pohľadávku voči pohľadávke veriteľa, a to aj v prípade, ak veriteľ uplatnil svoju pohľadávku voči inému spoludlžníkovi.</p><h2>Záver</h2><p>Pohľadávky je možné jednostranne započítať v prípade, ak sú vzájomné, smerujú k plneniu rovnakého druhu, sú spôsobilé na započítanie a strana, ktorá započítava, o svojom úmysle započítať pohľadávky informovala druhú stranu. Oznámenie musí obsahovať jasné určenie, ktoré pohľadávky sa započítavajú a v akej výške. Ak sa na tom strany dohodnú, je možné započítať akékoľvek ďalšie pohľadávky, ak je splnená podmienka vzájomnosti a v občianskoprávnych vzťahoch aj podmienka rovnakého druhu plnenia, kedy nedošlo k právnemu úkonu v rozpore so zákonom alebo dohodou strán.</p>',
        ARRAY['započítanie pohľadávok', 'obchodné právo', 'občiansky zákonník', 'záväzky'],
        TRUE
    );

    -- EN Translation
    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_3, 'en', 
        'When is it possible to set off claims',
        'The extinction of claims by set-off represents a form of non-cash settlement between the debtor and the creditor, where there is no real performance between them, which undoubtedly brings cost savings.',
        'The extinction of claims by set-off represents a form of non-cash settlement between the debtor and the creditor, where there is no real performance between them, which undoubtedly brings cost savings that these parties would otherwise have to incur. It could be said that it is a form of substitute performance of the obligation towards the creditor, by which their claim is satisfied. Given the relative simplicity and efficiency of fulfilling obligations in this way, it is an institute frequently used in practice. However, the legal conditions for its use are not always met.',
        'Commercial Law', '10 min read',
        '<h2>Introduction to the issue of set-off</h2><p>The extinction of claims by set-off represents a form of non-cash settlement between the debtor and the creditor, where there is no real performance between them, which undoubtedly brings cost savings that these parties would otherwise have to incur. It could be said that it is a form of substitute performance of the obligation towards the creditor, by which their claim is satisfied. Given the relative simplicity and efficiency of fulfilling obligations in this way, it is an institute frequently used in practice. However, the legal conditions for its use are not always met.</p><h2>Substantive legal conditions for set-off</h2><p>The basic prerequisite for fulfilling the obligation by set-off is compliance with substantive legal conditions. These conditions can be divided into general and special. The general conditions for set-off are:</p><ul><li>mutuality of claims</li><li>same type of performance</li><li>eligibility for set-off</li><li>the parties have made a certain manifestation of will aimed at the extinction of claims by set-off.</li></ul><p>The above general conditions for set-off follow from the provisions of § 580 and § 581 of the Civil Code. These are modified by the provisions of § 358 to § 364 of the Commercial Code or other relevant legal regulations.</p><h3>Mutuality of claims</h3><p>We speak of mutuality of claims when, between the same parties, each party is both a creditor and a debtor. The condition of mutuality of the claim must be met regardless of whether it is a unilateral set-off or a set-off agreement. The law establishes exceptions to the condition of mutuality, which regulate cases where there has been a change in the person of the creditor, for example, due to an assignment of a claim. In such a case, the debtor can set off against the assignee (new creditor) those claims that they had against the assignor at the time they learned of the assignment of the claim from the assignor to the assignee.</p><h3>Same type of performance</h3><p>Another legal condition is that the claims must be of the same type, i.e. their content is the same performance in terms of quantity and type. From the perspective of the type, it can be monetary claims, where their amount is expressed in money, or non-monetary claims, where their amount is expressed in other units, for example, in kilograms. Most often, it will be claims for monetary performance, and in commercial liability relations, set-off is not prevented even if the claims are in different currencies, provided that these currencies are freely convertible.</p><h3>Eligibility for set-off</h3><p>Claims are eligible for set-off when set-off is not excluded by law or by agreement of the participants. The agreement of the participants on the impossibility of setting off mutual claims represents a legal obstacle. The Civil Code, in provision § 581, paragraphs 1 and 2, regulates exclusions from unilateral set-off. According to § 581, paragraph 1, unilateral set-off is inadmissible against a claim for compensation for damage to health, unless it is a mutual claim for compensation for damage of the same type.</p><h2>Forms of set-off</h2><p>The set-off itself can occur by a unilateral act or by agreement of the parties. In case of unilateral set-off, all the mentioned conditions must be met.</p><h3>Unilateral set-off</h3><p>Unilateral set-off is effective against the other party from the moment it came into its disposition. Conversely, in the case of a party agreement, this agreement is effective from the moment of the effectiveness of the acceptance of the proposal by the other party, for example, the agreement becomes effective upon signature by the participants. However, the real effects of set-off are not associated with the moment of receipt of the notification of unilateral set-off or the conclusion of the agreement, but with the moment of the meeting of claims, i.e. the moment when the later of them became due.</p><h3>Set-off agreement</h3><p>The agreement on the set-off of claims must be signed by persons authorized to act for the company. It can be, for example, company executives, or persons authorized for this purpose, for example, an authorized employee, which follows from the job description or internal organizational documents.</p><h2>Special cases of set-off</h2><p>A claim can be set off even during an ongoing court proceeding or execution proceeding. The mere existence of an ongoing proceeding has no effect on the set-off of the claim. It is important that the claims were eligible for set-off at the moment they met, even if one of the claims was not later awarded by the court.</p><p>In case of passive solidary obligations, where several entities appear on the debtor''s side and the creditor is entitled to assert their claim for performance with any of them, any of the debtors can set off their claim against the creditor''s claim, even if the creditor asserted their claim against another co-debtor.</p><h2>Conclusion</h2><p>Claims can be unilaterally set off if they are mutual, directed towards performance of the same type, are eligible for set-off and the party that sets off has informed the other party of its intention to set off the claims. The notification must contain a clear identification of which claims are being set off and in what amount. If the parties agree on it, it is possible to set off any other claims, provided that the condition of mutuality is met and in civil law relations also the condition of the same type of performance, where the legal act was not performed contrary to the law or the agreement of the parties.</p>',
        ARRAY['set-off of claims', 'commercial law', 'civil code', 'obligations'],
        TRUE
    );

