    INSERT INTO public.legis_blog_translations (blog_id, lang, title, description, excerpt, category, reading_time, content, tags, is_published)
    VALUES (v_blog_id_3, 'de', 
        'Wann ist eine Aufrechnung von Forderungen möglich',
        'Das Erlöschen von Forderungen durch Aufrechnung stellt eine Form des bargeldlosen Ausgleichs zwischen Schuldner und Gläubiger dar, bei der es zu keiner realen Erfüllung zwischen ihnen kommt, was zweifellos Kostenersparnisse bringt.',
        'Das Erlöschen von Forderungen durch Aufrechnung stellt eine Form des bargeldlosen Ausgleichs zwischen Schuldner und Gläubiger dar, bei der es zu keiner realen Erfüllung zwischen ihnen kommt, was zweifellos Kostenersparnisse bringt, die diese Parteien andernfalls aufwenden müssten. Man könnte sagen, dass es sich um eine Form der Ersatzvornahme der Verpflichtung gegenüber dem Gläubiger handelt, durch die seine Forderung befriedigt wird. Angesichts der relativen Einfachheit und Effizienz der Erfüllung von Verpflichtungen auf diese Weise handelt es sich um ein in der Praxis häufig genutztes Institut. Die gesetzlichen Bedingungen für seine Nutzung werden jedoch nicht immer eingehalten.',
        'Handelsrecht', '10 min Lesezeit',
        '<h2>Einführung in das Thema der Aufrechnung</h2><p>Das Erlöschen von Forderungen durch Aufrechnung stellt eine Form des bargeldlosen Ausgleichs zwischen Schuldner und Gläubiger dar, bei der es zu keiner realen Erfüllung zwischen ihnen kommt, was zweifellos Kostenersparnisse bringt, die diese Parteien andernfalls aufwenden müssten. Man könnte sagen, dass es sich um eine Form der Ersatzvornahme der Verpflichtung gegenüber dem Gläubiger handelt, durch die seine Forderung befriedigt wird. Angesichts der relativen Einfachheit und Effizienz der Erfüllung von Verpflichtungen auf diese Weise handelt es sich um ein in der Praxis häufig genutztes Institut. Die gesetzlichen Bedingungen für seine Nutzung werden jedoch nicht immer eingehalten.</p><h2>Materiell-rechtliche Voraussetzungen für die Aufrechnung</h2><p>Grundvoraussetzung für die Erfüllung der Verpflichtung durch Aufrechnung ist die Einhaltung materiell-rechtlicher Bedingungen. Diese Bedingungen lassen sich in allgemeine und besondere unterteilen. Allgemeine Bedingungen für die Aufrechenbarkeit sind:</p><ul><li>Gegenseitigkeit der Forderungen</li><li>Gleichartigkeit der Leistung</li><li>Aufrechenbarkeit</li><li>die Parteien haben eine bestimmte Willenserklärung abgegeben, die auf das Erlöschen der Forderungen durch Aufrechnung gerichtet ist.</li></ul><p>Die oben genannten allgemeinen Bedingungen für die Aufrechenbarkeit ergeben sich aus den Bestimmungen der §§ 580 und 581 des Bürgerlichen Gesetzbuches. Diese werden durch die Bestimmungen der §§ 358 bis 364 des Handelsgesetzbuches oder andere einschlägige Rechtsvorschriften modifiziert.</p><h3>Gegenseitigkeit der Forderungen</h3><p>Von Gegenseitigkeit der Forderungen sprechen wir, wenn zwischen denselben Parteien jede Partei gleichzeitig Gläubiger und Schuldner ist. Die Bedingung der Gegenseitigkeit der Forderung muss unabhängig davon erfüllt sein, ob es sich um eine einseitige Aufrechnung oder eine Aufrechnungsvereinbarung handelt. Das Gesetz sieht Ausnahmen von der Bedingung der Gegenseitigkeit vor, die Fälle regeln, in denen ein Wechsel in der Person des Gläubigers eingetreten ist, beispielsweise aufgrund einer Forderungsabtretung. In einem solchen Fall kann der Schuldner gegenüber dem Zessionar (neuer Gläubiger) diejenigen Forderungen aufrechnen, die er gegenüber dem Zedenten zu dem Zeitpunkt hatte, als er von der Forderungsabtretung vom Zedenten an den Zessionar erfahren hat.</p><h3>Gleichartigkeit der Leistung</h3><p>Eine weitere gesetzliche Bedingung ist, dass die Forderungen gleichartig sein müssen, d. h. ihr Inhalt ist die gleiche Leistung in Bezug auf Menge und Art. In Bezug auf die Art kann es sich um Geldforderungen handeln, bei denen ihr Betrag in Geld ausgedrückt wird, oder um Nicht-Geldforderungen, bei denen ihr Betrag in anderen Einheiten, beispielsweise in Kilogramm, ausgedrückt wird. Am häufigsten handelt es sich um Forderungen auf Geldleistung, und in Handels-Schuldverhältnissen steht der Aufrechnung auch nicht entgegen, wenn die Forderungen in verschiedenen Währungen bestehen, sofern diese Währungen frei konvertierbar sind.</p><h3>Aufrechenbarkeit</h3><p>Forderungen sind aufrechenbar, wenn die Aufrechnung nicht durch Gesetz oder Vereinbarung der Beteiligten ausgeschlossen ist. Die Vereinbarung der Beteiligten über die Unmöglichkeit, gegenseitige Forderungen aufzurechnen, stellt ein gesetzliches Hindernis dar. Das Bürgerliche Gesetzbuch regelt in der Bestimmung des § 581 Abs. 1 und Abs. 2 Ausschlüsse von der einseitigen Aufrechnung. Gemäß § 581 Abs. 1 ist eine einseitige Aufrechnung gegen eine Forderung auf Ersatz von Gesundheitsschäden unzulässig, es sei denn, es handelt sich um eine gegenseitige Forderung auf Schadenersatz der gleichen Art.</p><h2>Formen der Aufrechnung</h2><p>Die Aufrechnung selbst kann durch einseitige Handlung oder durch Vereinbarung der Parteien erfolgen. Bei der einseitigen Aufrechnung müssen alle genannten Bedingungen erfüllt sein.</p><h3>Einseitige Aufrechnung</h3><p>Die einseitige Aufrechnung wird gegenüber der anderen Partei ab dem Zeitpunkt wirksam, zu dem sie in deren Verfügungsbereich gelangt ist. Umgekehrt ist im Falle einer Parteivereinbarung diese Vereinbarung ab dem Zeitpunkt der Wirksamkeit der Annahme des Vorschlags durch die andere Partei wirksam, beispielsweise wird die Vereinbarung mit der Unterzeichnung durch die Beteiligten wirksam. Die realen Wirkungen der Aufrechnung sind jedoch nicht mit dem Zeitpunkt des Zugangs der Mitteilung über die einseitige Aufrechnung oder dem Abschluss der Vereinbarung verbunden, sondern mit dem Zeitpunkt des Zusammentreffens der Forderungen, d. h. dem Zeitpunkt, zu dem die spätere von ihnen fällig wurde.</p><h3>Aufrechnungsvereinbarung</h3><p>Die Vereinbarung über die Aufrechnung von Forderungen muss von Personen unterzeichnet werden, die berechtigt sind, für das Unternehmen zu handeln. Dies können beispielsweise Geschäftsführer von Gesellschaften oder zu diesem Zweck bevollmächtigte Personen sein, beispielsweise ein bevollmächtigter Mitarbeiter, was sich aus der Stellenbeschreibung oder internen Organisationsunterlagen ergibt.</p><h2>Besondere Fälle der Aufrechnung</h2><p>Eine Forderung kann auch während eines laufenden Gerichtsverfahrens oder Vollstreckungsverfahrens aufgerechnet werden. Das bloße Bestehen eines laufenden Verfahrens hat keinen Einfluss auf die Aufrechenbarkeit der Forderung. Wichtig ist, dass die Forderungen in dem Moment, in dem sie zusammentrafen, aufrechenbar waren, auch wenn eine der Forderungen später vom Gericht nicht anerkannt wurde.</p><p>Im Falle passiver Solidarverpflichtungen, bei denen auf der Schuldnerseite mehrere Rechtsträger auftreten und der Gläubiger berechtigt ist, seine Forderung auf Leistung bei jedem von ihnen geltend zu machen, kann jeder der Schuldner seine Forderung gegen die Forderung des Gläubigers aufrechnen, auch wenn der Gläubiger seine Forderung gegen einen anderen Mitschuldner geltend gemacht hat.</p><h2>Fazit</h2><p>Forderungen können einseitig aufgerechnet werden, wenn sie gegenseitig sind, auf die gleiche Art der Leistung gerichtet sind, aufrechenbar sind und die Partei, die aufrechnet, die andere Partei über ihre Absicht, die Forderungen aufzurechnen, informiert hat. Die Mitteilung muss eine klare Identifizierung darüber enthalten, welche Forderungen in welcher Höhe aufgerechnet werden. Wenn sich die Parteien darauf einigen, ist es möglich, alle anderen Forderungen aufzurechnen, sofern die Bedingung der Gegenseitigkeit erfüllt ist und in zivilrechtlichen Verhältnissen auch die Bedingung der Gleichartigkeit der Leistung, wobei die Rechtshandlung nicht im Widerspruch zum Gesetz oder der Vereinbarung der Parteien vorgenommen wurde.</p>',
        ARRAY['Aufrechnung von Forderungen', 'Handelsrecht', 'Bürgerliches Gesetzbuch', 'Verpflichtungen'],
        TRUE
    );

